/**
 * @param {number[][]} points
 * @param {number[]} target
 * @return {number}
 */
function solve(points, target) {
    // Helper function to check if two points are equal
    const isEqual = (p1, p2) => p1[0] === p2[0] && p1[1] === p2[1] && p1[2] === p2[2];

    // Convert points array to a Set for O(1) average time complexity lookups
    // Since coordinates are small (<= 6), a string representation works well as a unique key.
    const initialPointsSet = new Set();
    for (const point of points) {
        initialPointsSet.add(point.join(','));
    }

    // Check if target is in the 0th generation
    const targetKey = target.join(',');
    if (initialPointsSet.has(targetKey)) {
        return 0;
    }

    // currentPoints will hold the set of unique points available up to the current generation (k-1)
    // Initially, it contains all points from generation 0.
    let currentPoints = new Set(points.map(p => p.join(',')));

    // Maximum iterations check (safety limit, though the search space is small)
    // With coordinates up to 6, the number of unique points is finite, and we expect convergence or cycling.
    // Given the constraints (0 <= x, y, z <= 6), there are only 7^3 = 343 possible points.
    const MAX_GENERATIONS = 350; 

    for (let k = 1; k <= MAX_GENERATIONS; k++) {
        const pointsArray = Array.from(currentPoints).map(key => key.split(',').map(Number));
        const newPoints = new Set();
        let targetFoundInThisGeneration = false;

        const n = pointsArray.length;

        if (n < 2) {
            // Cannot generate any new points if less than 2 unique points exist.
            break; 
        }

        // Generate points for generation k
        // Iterate over all unique pairs (a, b) from all points generated up to generation k-1
        for (let i = 0; i < n; i++) {
            for (let j = 0; j < n; j++) {
                // Must be two *different* points. The problem states:
                // "select the two different points"
                // "two different points" means they must have different (x, y, z) coordinates.
                if (i === j) continue; // Skip pairing a with itself

                const p1 = pointsArray[i];
                const p2 = pointsArray[j];

                // Check if p1 and p2 have different coordinates.
                // Since pointsArray is derived from a Set of unique string representations, 
                // p1 and p2 must already have different coordinates if i != j, 
                // because the initial input guarantees no duplicates, and the generation process
                // only adds calculated averages, which are unique keys in the Set.
                // If pointsArray[i] === pointsArray[j], then i must equal j, which we skip.
                // Therefore, i != j implies different points according to the problem's definition 
                // regarding "different (x, y, z) coordinates".

                // Calculate the midpoint c = [floor((x1 + x2) / 2), floor((y1 + y2) / 2), floor((z1 + z2) / 2)]
                const cx = Math.floor((p1[0] + p2[0]) / 2);
                const cy = Math.floor((p1[1] + p2[1]) / 2);
                const cz = Math.floor((p1[2] + p2[2]) / 2);

                const c = [cx, cy, cz];
                const cKey = c.join(',');

                // Check if target is found
                if (cKey === targetKey) {
                    targetFoundInThisGeneration = true;
                }

                // Add to new points set, even if target was found, as we need all points for future generations
                newPoints.add(cKey);
            }
        }

        if (targetFoundInThisGeneration) {
            return k;
        }

        // Update currentPoints for the next iteration (k+1)
        // The next generation uses ALL points from generation 0 up to generation k.
        // currentPoints already holds points up to k-1. We add the newly generated points (generation k).
        for (const pointKey of newPoints) {
            currentPoints.add(pointKey);
        }

        // Optimization: If the set of unique points stops growing, we won't find the target unless it was already found.
        // This check is implicit by the MAX_GENERATIONS limit, but good practice if coordinates were larger.
    }

    return -1;
}

