import kotlin.math.floor

fun solve(points: Array<Array<Long>>, target: Array<Long>): Long {
    // Helper function to convert a point array [x, y, z] to a unique string key
    fun pointToKey(p: Array<Long>): String = "${p[0]},${p[1]},${p[2]}"

    // Convert target to its key
    val targetKey = pointToKey(target)

    // Set of all unique points available up to the current generation (represented by their keys)
    // Initially, it contains all points from generation 0.
    val currentPointsKeys = mutableSetOf<String>()
    for (p in points) {
        val key = pointToKey(p)
        currentPointsKeys.add(key)
    }

    // Check if target is in the 0th generation
    if (currentPointsKeys.contains(targetKey)) {
        return 0L
    }

    // Maximum possible points based on constraints (0 to 6 in 3D) is 7^3 = 343.
    // Since we are always adding new points or reaching a stable set, we set a safe iteration limit.
    val MAX_GENERATIONS = 350

    for (k in 1..MAX_GENERATIONS) {
        // Convert keys back to point arrays for calculation
        val pointsArray = currentPointsKeys.map { key ->
            val parts = key.split(',').map { it.toLong() }.toLongArray()
            parts
        }.toTypedArray()

        val newPointsKeys = mutableSetOf<String>()
        var targetFoundInThisGeneration = false

        val n = pointsArray.size

        if (n < 2) {
            // Cannot generate any new points if less than 2 unique points exist.
            break
        }

        // Generate points for generation k
        // Iterate over all unique pairs (a, b) from the set of unique points available (Generation 0 to k-1)
        for (i in 0 until n) {
            for (j in 0 until n) {
                // Must be two *different* points (different coordinates)
                if (i == j) continue

                val p1 = pointsArray[i]
                val p2 = pointsArray[j]

                // Since pointsArray is derived from a Set of unique keys, i != j guarantees different coordinates.

                // Calculate the midpoint c = [floor((x1 + x2) / 2), floor((y1 + y2) / 2), floor((z1 + z2) / 2)]
                val cx = floor((p1[0] + p2[0]) / 2.0).toLong()
                val cy = floor((p1[1] + p2[1]) / 2.0).toLong()
                val cz = floor((p1[2] + p2[2]) / 2.0).toLong()

                val c = longArrayOf(cx, cy, cz)
                val cKey = pointToKey(c)

                // Check if target is found (must be a newly generated point or already existing one)
                // The rule implies checking if it's generated in step k, but since we are collecting *all*
                // points up to k, we check if it's in the newly generated set or already present.
                // If it's in newPointsKeys, it was generated in this step.
                if (cKey == targetKey) {
                    targetFoundInThisGeneration = true
                }

                // Add to the set of newly generated points for this step.
                newPointsKeys.add(cKey)
            }
        }

        if (targetFoundInThisGeneration) {
            return k.toLong()
        }

        // Update currentPointsKeys for the next iteration (k+1)
        // The next generation uses ALL points from generation 0 up to generation k.
        // We merge the newly generated unique points into the set.
        currentPointsKeys.addAll(newPointsKeys)

        // Check for stability (if no new points were generated in this step)
        if (newPointsKeys.size == 0) {
            break
        }
    }

    return -1L
}
